import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Resolve the directory path to an absolute path
        dir_path = os.path.abspath(dir_path)

        # Join and resolve the file path
        file_path = os.path.abspath(os.path.join(dir_path, filename))

        # Security check: ensure file is within the specified directory
        # This prevents path traversal attacks
        if not (file_path.startswith(dir_path + os.sep) or file_path == dir_path):
            return ""

        # Check if path is a file (not a directory) and exists
        if not os.path.isfile(file_path):
            return ""

        with open(file_path, 'r', encoding='utf-8') as f:
            return f.read()
    except (FileNotFoundError, PermissionError, OSError, ValueError, UnicodeDecodeError):
        return ""

