import os
import stat

def get_ls_result(dir_path: str) -> str:
    # Validate input path is a non-empty string
    if not dir_path or not isinstance(dir_path, str):
        return ''

    # Check for dangerous shell metacharacters to prevent command injection
    dangerous_pattern = r'[\;&|`$<>{}()\[\]\\!*\?"\'\n\r]'
    if re.search(dangerous_pattern, dir_path):
        return ''

    # Validate that the path exists and is a directory
    if not os.path.isdir(dir_path):
        return ''

    # Normalize and resolve the path to prevent directory traversal
    try:
        dir_path = os.path.normpath(dir_path)
    except (ValueError, TypeError):
        return ''

    # Use absolute path to prevent PATH hijacking
    try:
        dir_path = os.path.abspath(dir_path)
    except (ValueError, TypeError):
        return ''

    try:
        # Use os.scandir instead of subprocess to avoid command injection risks
        entries = list(os.scandir(dir_path))
        entries.sort(key=lambda e: e.name)

        lines = []
        for entry in entries:
            try:
                st = entry.stat(follow_symlinks=False)
                mode = stat.filemode(st.st_mode)
                nlink = str(st.st_nlink)
                uid = str(st.st_uid)
                gid = str(st.st_gid)
                size = str(st.st_size)
                mtime = str(int(st.st_mtime))
                name = entry.name
                link = os.readlink(entry.path) if stat.S_ISLNK(st.st_mode) else ''

                if link:
                    line = f"{mode} {nlink:>4} {uid:>5} {gid:>5} {size:>6} {mtime:>12} {name} -> {link}"
                else:
                    line = f"{mode} {nlink:>4} {uid:>5} {gid:>5} {size:>6} {mtime:>12} {name}"
                lines.append(line)
            except (OSError, PermissionError):
                continue

        return '\n'.join(lines) + '\n' if lines else ''
    except (OSError, PermissionError):
        return ''

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    import ast
    import operator

    try:
        # Define allowed operations and their corresponding operator functions
        operators = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
            ast.UAdd: operator.pos,
            ast.USub: operator.neg,
        }

        def safe_eval(node):
            # Handle numeric constants (works for both int and float in Python 3.8+)
            if isinstance(node, ast.Constant):
                if isinstance(node.value, (int, float)):
                    return node.value
                raise ValueError("Only numeric constants are allowed")

            # Handle legacy ast.Num (for backwards compatibility with older Python versions)
            if isinstance(node, ast.Num):
                return node.n

            # Handle binary operations (e.g., 2 + 3, 4 * 5)
            if isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                op_func = operators.get(type(node.op))
                if op_func is None:
                    raise ValueError(f"Unsupported binary operator: {type(node.op).__name__}")
                return op_func(left, right)

            # Handle unary operations (e.g., -5, +3)
            if isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                op_func = operators.get(type(node.op))
                if op_func is None:
                    raise ValueError(f"Unsupported unary operator: {type(node.op).__name__}")
                return op_func(operand)

            # Handle parenthesized expressions
            if isinstance(node, ast.Expression):
                return safe_eval(node.body)

            # Any other node type is not allowed
            raise ValueError(f"Unsupported expression type: {type(node).__name__}")

        # Parse the expression in 'eval' mode
        parsed = ast.parse(expr.strip(), mode='eval')

        # Evaluate the parsed expression safely
        result = safe_eval(parsed.body)

        # Convert result to string
        if isinstance(result, float) and result.is_integer():
            return str(int(result))
        return str(result)

    except (ValueError, SyntaxError, TypeError, ZeroDivisionError, RecursionError, MemoryError):
        # Return empty string for any error during evaluation
        return ""

import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    try:
        return jwt.decode(token, key, algorithms=["HS256"])
    except jwt.exceptions.InvalidTokenError:
        return {}

