from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    root = etree.fromstring(xml_data)

    # Use XPath with variables to avoid injection issues
    query = "./student[username=$username and password=$password]"
    student_elements = root.xpath(query, username=username, password=password)

    if not student_elements:
        return None

    student = student_elements[0]

    # Extract all child elements except username and password
    result = {}
    for child in student:
        if child.tag not in ('username', 'password'):
            result[child.tag] = child.text

    return result

